import ActivitySmith from "activitysmith";

const activitysmith = new ActivitySmith({
  apiKey: process.env.ACTIVITYSMITH_API_KEY,
});

const start = await activitysmith.liveActivities.start({
  content_state: {
    title: "Nightly database backup",
    subtitle: "create snapshot",
    number_of_steps: 3,
    current_step: 1,
    type: "segmented_progress",
    color: "yellow",
  },
});

const activityId = start.activity_id;

package main

import (
	"log"

	activitysmithsdk "github.com/ActivitySmithHQ/activitysmith-go"
)

func main() {
	activitysmith, err := activitysmithsdk.New("YOUR-API-KEY")
	if err != nil {
		log.Fatal(err)
	}

	start, err := activitysmith.LiveActivities.Start(activitysmithsdk.LiveActivityStartInput{
		Title:         "Nightly database backup",
		Subtitle:      "create snapshot",
		NumberOfSteps: 3,
		CurrentStep:   1,
		Type:          "segmented_progress",
		Color:         "yellow",
	})
	if err != nil {
		log.Fatal(err)
	}

	activityID := start.GetActivityId()
	_ = activityID
}

